import React, { createContext, useState, useRef, useContext, useEffect } from 'react';
import axios from 'axios';

const MusicContext = createContext();

export const MusicProvider = ({ children }) => {
  const [songs, setSongs] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(-1);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentSong, setCurrentSong] = useState(null);
  const [favorites, setFavorites] = useState([]); // Lưu mảng các ID bài hát đã thích
  const audioRef = useRef(null);

  const loggedInUser = JSON.parse(localStorage.getItem('user'));

  // 1. Tải danh sách yêu thích khi khởi động hoặc khi user đăng nhập
  useEffect(() => {
    const fetchFavorites = async () => {
      if (loggedInUser) {
        try {
          const userId = loggedInUser._id || loggedInUser.id;
          const res = await axios.get(`http://localhost:5000/api/auth/${userId}/favorites`);
          // Lưu lại mảng ID bài hát để kiểm tra nhanh bằng .includes()
          setFavorites(res.data.map(song => song._id));
        } catch (err) {
          console.error("Lỗi tải danh sách yêu thích:", err);
        }
      }
    };
    fetchFavorites();
  }, []);

  // 2. Tự động phát nhạc khi thay đổi bài hát
  useEffect(() => {
    if (currentSong && isPlaying && audioRef.current) {
      const playPromise = audioRef.current.play();
      if (playPromise !== undefined) {
        playPromise.catch(error => {
          console.error("Auto-play bị chặn:", error);
          setIsPlaying(false);
        });
      }
    }
  }, [currentSong]);

  // 3. Hàm kích hoạt phát nhạc từ danh sách
  const playMusic = (songList, index) => {
    if (!songList || songList.length === 0) return;
    setSongs(songList);
    setCurrentIndex(index);
    setCurrentSong(songList[index]);
    setIsPlaying(true);
  };

  // 4. Điều khiển Play/Pause
  const togglePlay = () => {
    if (!currentSong) return;
    if (isPlaying) {
      audioRef.current.pause();
      setIsPlaying(false);
    } else {
      audioRef.current.play()
        .then(() => setIsPlaying(true))
        .catch(err => console.error("Lỗi khi phát:", err));
    }
  };

  // 5. CHỨC NĂNG THẢ TIM (Favorites)
  const toggleLike = async (songId) => {
    if (!loggedInUser) return alert("Vui lòng đăng nhập để thả tim!");
    try {
      const userId = loggedInUser._id || loggedInUser.id;
      const res = await axios.post('http://localhost:5000/api/auth/toggle-favorite', {
        userId,
        songId
      });
      // Cập nhật lại mảng ID favorites từ phản hồi của server
      setFavorites(res.data.favorites);
    } catch (err) {
      console.error("Lỗi khi toggle favorite:", err);
    }
  };

  const handleNext = () => {
    if (songs.length === 0) return;
    const nextIndex = (currentIndex + 1) % songs.length;
    setCurrentIndex(nextIndex);
    setCurrentSong(songs[nextIndex]);
    setIsPlaying(true);
  };

  const handlePrev = () => {
    if (songs.length === 0) return;
    const prevIndex = (currentIndex - 1 + songs.length) % songs.length;
    setCurrentIndex(prevIndex);
    setCurrentSong(songs[prevIndex]);
    setIsPlaying(true);
  };

  return (
    <MusicContext.Provider value={{ 
      songs, currentSong, isPlaying, setIsPlaying, currentIndex, 
      audioRef, playMusic, togglePlay, handleNext, handlePrev,
      favorites, toggleLike // Cung cấp cho các component khác sử dụng
    }}>
      {children}
      {/* Thẻ audio ẩn xử lý phát nhạc toàn cục */}
      {currentSong && (
        <audio
          ref={audioRef}
          src={`http://localhost:5000${currentSong.musicUrl}`}
          onEnded={handleNext}
        />
      )}
    </MusicContext.Provider>
  );
};

export const useMusic = () => useContext(MusicContext);
